def resolve_territories(territories, landmarks):
    def cross(O, A, B):
        return (A[0] - O[0]) * (B[1] - O[1]) - (A[1] - O[1]) * (B[0] - O[0])

    def convex_hull(points):
        points = sorted(set(map(tuple, points)))
        if len(points) <= 1:
            return points
        lower = []
        for p in points:
            while len(lower) >= 2 and cross(lower[-2], lower[-1], p) <= 0:
                lower.pop()
            lower.append(p)
        upper = []
        for p in reversed(points):
            while len(upper) >= 2 and cross(upper[-2], upper[-1], p) <= 0:
                upper.pop()
            upper.append(p)
        return lower[:-1] + upper[:-1]

    def point_in_convex_hull(hull, point):
        n = len(hull)
        if n == 0:
            return False
        if n == 1:
            return hull[0][0] == point[0] and hull[0][1] == point[1]
        if n == 2:
            c = cross(hull[0], hull[1], point)
            if c != 0:
                return False
            min_x = min(hull[0][0], hull[1][0])
            max_x = max(hull[0][0], hull[1][0])
            min_y = min(hull[0][1], hull[1][1])
            max_y = max(hull[0][1], hull[1][1])
            return min_x <= point[0] <= max_x and min_y <= point[1] <= max_y
        for i in range(n):
            if cross(hull[i], hull[(i + 1) % n], point) < 0:
                return False
        return True

    hulls = [convex_hull(t) for t in territories]
    results = []
    for lm in landmarks:
        lm = tuple(lm)
        containing = []
        for i, hull in enumerate(hulls):
            if point_in_convex_hull(hull, lm):
                containing.append(i)
        if len(containing) == 0:
            results.append("unclaimed")
        elif len(containing) == 1:
            results.append(containing[0])
        else:
            results.append("disputed")
    return results
